/* eslint-disable @next/next/no-img-element */
import Link from "next/link";

import {
  DepartmentCarousel,
  QuickCategoriesCarousel,
} from "@/components/home/StorefrontHomeCarousels";
import { ProductCard } from "@/components/ui/ProductCard";
import { getServerLanguage } from "@/lib/server-language";
import {
  getActiveBanners,
  getFeaturedCategories,
  getNewArrivalProducts,
  getOfferProducts,
} from "@/lib/storefront-data";
import { getMessages, getProductName } from "@/lib/storefront";
import { cn } from "@/lib/utils";

export const dynamic = "force-dynamic";

export default async function HomePage() {
  const language = await getServerLanguage();
  const messages = getMessages(language);
  const [banners, categories, offers, newArrivals] = await Promise.all([
    getActiveBanners(),
    getFeaturedCategories(),
    getOfferProducts(8),
    getNewArrivalProducts(8),
  ]);

  const heroBanner = banners[0] ?? null;
  const heroProduct = offers[0] ?? newArrivals[0] ?? null;
  const fallbackCategory = categories.find((category) => category.image_url);
  const bannerVisual =
    heroBanner?.image_url ??
    fallbackCategory?.image_url ??
    heroProduct?.image_url ??
    null;
  const bannerAlt =
    heroBanner?.title ||
    (heroProduct
      ? getProductName(heroProduct, language)
      : language === "ar"
        ? "بانر الأمل سنتر"
        : "Al Amal Center banner");
  const secondaryBanners = banners.slice(1);
  const textAlignClass = language === "ar" ? "text-right" : "text-left";
  const sectionHeaderClass = cn(
    "mb-6 flex flex-col gap-4",
    language === "ar"
      ? "sm:flex-row-reverse sm:items-end sm:justify-between"
      : "sm:flex-row sm:items-end sm:justify-between"
  );

  return (
    <div className="space-y-10 lg:space-y-14">
      <section className="section-space pb-2 pt-4 lg:pt-8">
        {heroBanner ? (
          <div className="space-y-4 lg:space-y-5">
            <Link
              href={heroBanner.link || "/products"}
              className="group block overflow-hidden rounded-[2.75rem] border border-white/80 bg-white shadow-premium"
            >
              <img
                src={heroBanner.image_url}
                alt={heroBanner.title || bannerAlt}
                className="h-auto w-full transition duration-700 group-hover:scale-[1.02]"
                loading="eager"
              />
            </Link>

            {secondaryBanners.length > 0 ? (
              <div className="grid gap-4 sm:grid-cols-2 xl:grid-cols-3">
                {secondaryBanners.map((banner) => (
                  <Link
                    key={banner.id}
                    href={banner.link || "/products"}
                    className="group overflow-hidden rounded-[2.2rem] border border-white/80 bg-white shadow-soft transition duration-300 hover:-translate-y-1 hover:shadow-premium"
                  >
                    <img
                      src={banner.image_url}
                      alt={
                        banner.title ||
                        (language === "ar"
                          ? "بانر الأمل سنتر"
                          : "Al Amal Center banner")
                      }
                      className="h-full w-full object-cover transition duration-700 group-hover:scale-[1.03]"
                      loading="lazy"
                    />
                  </Link>
                ))}
              </div>
            ) : null}
          </div>
        ) : (
          <Link
            href="/products"
            className="group block overflow-hidden rounded-[2.75rem] border border-white/80 bg-white shadow-premium"
          >
            {bannerVisual ? (
              <img
                src={bannerVisual}
                alt={bannerAlt}
                className="h-auto w-full transition duration-700 group-hover:scale-[1.02]"
                loading="eager"
              />
            ) : (
              <div className="h-[14rem] bg-[linear-gradient(135deg,#f8faf8_0%,#edf7ee_45%,#fdf7e7_100%)] sm:h-[18rem] lg:h-[24rem] xl:h-[28rem]" />
            )}
          </Link>
        )}
      </section>

      <section className="section-space py-2">
        <div className={textAlignClass}>
          <p className="eyebrow">{messages.home.quickCategories}</p>
          <h2 className="section-heading mt-3">{messages.home.quickCategories}</h2>
        </div>

        {categories.length > 0 ? (
          <QuickCategoriesCarousel categories={categories} language={language} />
        ) : (
          <div className="soft-panel mt-6 px-6 py-14 text-center text-slate-500">
            {messages.home.noCategories}
          </div>
        )}
      </section>

      <section className="section-space py-2">
        <div className={sectionHeaderClass}>
          <div className={textAlignClass}>
            <p className="eyebrow">{messages.home.offers}</p>
            <h2 className="section-heading mt-3">{messages.home.offers}</h2>
          </div>
          <Link href="/products" className="pill-button-ghost">
            {messages.common.viewAll}
          </Link>
        </div>

        {offers.length > 0 ? (
          <div className="grid grid-cols-1 gap-6 md:grid-cols-2 xl:grid-cols-4">
            {offers.slice(0, 8).map((product) => (
              <ProductCard key={product.id} product={product} />
            ))}
          </div>
        ) : (
          <div className="soft-panel px-6 py-14 text-center text-slate-500">
            {messages.home.noOffers}
          </div>
        )}
      </section>

      <section className="section-space py-2">
        <div className={textAlignClass}>
          <p className="eyebrow">{messages.home.categories}</p>
          <h2 className="section-heading mt-3">{messages.home.categories}</h2>
        </div>

        {categories.length > 0 ? (
          <DepartmentCarousel categories={categories} language={language} />
        ) : (
          <div className="soft-panel mt-6 px-6 py-14 text-center text-slate-500">
            {messages.home.noCategories}
          </div>
        )}
      </section>

      <section className="section-space pt-2">
        <div className={sectionHeaderClass}>
          <div className={textAlignClass}>
            <p className="eyebrow">{messages.home.newArrivals}</p>
            <h2 className="section-heading mt-3">{messages.home.newArrivals}</h2>
          </div>
          <Link href="/products?sort=newest" className="pill-button-ghost">
            {messages.common.viewAll}
          </Link>
        </div>

        {newArrivals.length > 0 ? (
          <div className="grid grid-cols-1 gap-6 md:grid-cols-2 xl:grid-cols-4">
            {newArrivals.map((product) => (
              <ProductCard key={product.id} product={product} />
            ))}
          </div>
        ) : (
          <div className="soft-panel px-6 py-14 text-center text-slate-500">
            {language === "ar"
              ? "لا توجد منتجات حديثة حالياً."
              : "No recent products are available right now."}
          </div>
        )}
      </section>
    </div>
  );
}
